// COMPLETE, COMPILABLE C code
#include <stdio.h>
int main() {
    int N;
    scanf("%d", &N);
    int A[N];
    for (int i = 0; i < N; i++) {
        scanf("%d", &A[i]);
    }
    int count = 0;
    for (int i = 0; i < N; i++) {
        for (int j = i; j < N; j++) {
            int freq[1000001] = {0};
            for (int k = i; k <= j; k++) {
                freq[A[k]]++;
            }
            int max_freq = 0;
            for (int k = 1; k <= 1000000; k++) {
                if (freq[k] > max_freq) {
                    max_freq = freq[k];
                }
            }
            if (max_freq > (j - i + 1) / 2) {
                count++;
            }
        }
    }
    printf("%d\n", count);
    return 0;
}

